      return;
    }
  }

  @override
  HttpAuthHandler pigeon_copy() {
    return HttpAuthHandler.pigeon_detached(
      pigeon_binaryMessenger: pigeon_binaryMessenger,
      pigeon_instanceManager: pigeon_instanceManager,
    );
  }
}
